let refscilinkState = {
  references: [],
  labels: REFSCILINK_I18N.en,
  validation: {}
};

// ==========================================================
// Data loading
// ==========================================================

async function loadReferences() {
  const response = await fetch(REFSCILINK_REFERENCES_PATH);
  if (!response.ok) {
    throw new Error(`${REFSCILINK_REFERENCES_PATH}: ${response.status}`);
  }
  const data = await response.json();
  return Array.isArray(data) ? data : data.references || [];
}

// Maps internal JSON values to i18n keys for badge display.
const REFSCILINK_BADGE_I18N = {
  validation: {
    pending_validation: "statusPending",
    validated:          "statusValidated",
    needs_revision:     "statusRevision",
    rejected:           "statusRejected"
  },
  access: {
    open_access:             "accessOpen",
    abstract_only:           "accessAbstract",
    accepted_author_version: "accessAuthor",
    preprint:                "accessPreprint",
    paywalled:               "accessPaywall",
    unknown:                 "accessUnknown"
  },
  theme: {
    unclassified: "themeUnclassified"
  }
};

function translateBadgeValue(type, value) {
  const key = REFSCILINK_BADGE_I18N[type]?.[value];
  return key ? (refscilinkState.labels[key] || value) : value;
}

function applyI18n() {
  document.querySelectorAll("[data-refscilink-i18n]").forEach(el => {
    const key = el.dataset.refscilinkI18n;
    const value = refscilinkState.labels[key];
    if (value && typeof value === "string") el.textContent = value;
  });
  document.querySelectorAll("[data-refscilink-i18n-placeholder]").forEach(el => {
    const key = el.dataset.refscilinkI18nPlaceholder;
    const value = refscilinkState.labels[key];
    if (value && typeof value === "string") el.placeholder = value;
  });
  document.querySelectorAll("[data-refscilink-i18n-aria]").forEach(el => {
    const key = el.dataset.refscilinkI18nAria;
    const value = refscilinkState.labels[key];
    if (value && typeof value === "string") el.setAttribute("aria-label", value);
  });
}

function detectCurrentPage() {
  return document.querySelector("[data-refscilink-page]")?.dataset.refscilinkPage || "unknown";
}

function detectLanguage() {
  const lang = document.documentElement.lang || "en";
  return lang.toLowerCase().startsWith("fr") ? "fr" : "en";
}

function getLocalizedLabels() {
  return REFSCILINK_I18N[detectLanguage()] || REFSCILINK_I18N.en;
}

// ==========================================================
// Rendering: index page
// ==========================================================

function renderIndexPage() {
  populateFilterOptions();
  bindIndexEvents();
  renderFilteredReferences();
}

function renderFilteredReferences() {
  const filtered = applyFilters(refscilinkState.references);
  const list = document.querySelector("[data-refscilink-list]");
  const count = document.querySelector("[data-refscilink-count]");
  if (!list) return;

  list.textContent = "";
  filtered.forEach(reference => list.appendChild(renderReferenceCard(reference)));
  if (count) count.textContent = refscilinkState.labels.count(filtered.length);
  setPageState(filtered.length ? "ready" : "empty");
}

function renderReferenceCard(reference) {
  const card = document.createElement("article");
  card.className = "refscilink-reference-card";
  card.dataset.refscilinkReferenceCard = reference.id;

  const validationStatus = getValidationStatus(reference);
  const accessType = reference.access_type || "unknown";
  const theme = reference.theme || "unclassified";

  const badges = document.createElement("div");
  badges.append(
    createBadge(`#${reference.number}`, "refscilink-badge"),
    createBadge(translateBadgeValue("theme", theme), "refscilink-badge refscilink-badge-theme"),
    createBadge(translateBadgeValue("access", accessType), `refscilink-badge refscilink-badge-access refscilink-access-${normalizeClass(accessType)}`),
    createBadge(translateBadgeValue("validation", validationStatus), `refscilink-badge refscilink-badge-validation refscilink-status-${normalizeClass(validationStatus)}`)
  );

  const title = document.createElement("h2");
  title.className = "refscilink-reference-title";
  title.textContent = reference.title || reference.raw_reference || reference.id;

  const meta = document.createElement("p");
  meta.className = "refscilink-reference-meta";
  meta.textContent = [reference.authors?.join(", "), reference.year, reference.journal].filter(Boolean).join(" — ");

  const summary = document.createElement("p");
  summary.textContent = reference.short_summary || reference.raw_reference || "";

  const actions = document.createElement("div");
  actions.className = "refscilink-reference-actions";
  actions.append(
    createInternalLink(`./reference.html?id=${encodeURIComponent(reference.id)}`, refscilinkState.labels.readSummary),
    createSourceLink(reference),
    createButton(refscilinkState.labels.copyReference, () => copyReferenceToClipboard(reference)),
    createButton(refscilinkState.labels.validateSummary, () => validateReference(reference.id))
  );

  card.append(badges, title, meta, summary, actions);
  return card;
}

function populateFilterOptions() {
  populateSelect("[data-refscilink-theme-filter]", uniqueValues("theme"));
  populateSelect("[data-refscilink-access-filter]", uniqueValues("access_type"));
}

function populateSelect(selector, values) {
  const select = document.querySelector(selector);
  if (!select) return;
  const existing = new Set([...select.options].map(option => option.value));
  values.filter(Boolean).sort().forEach(value => {
    if (existing.has(value)) return;
    const option = document.createElement("option");
    option.value = value;
    option.textContent = value;
    select.appendChild(option);
  });
}

function uniqueValues(key) {
  return [...new Set(refscilinkState.references.map(reference => reference[key] || ""))];
}

// ==========================================================
// Rendering: detail page
// ==========================================================

function renderDetailPage() {
  const reference = findReferenceById(getReferenceIdFromUrl());
  if (!reference) {
    setPageState("not_found");
    return;
  }

  document.title = `${reference.title || reference.id} — ${refscilinkState.labels.references}`;
  document.querySelector("[data-refscilink-detail-title]").textContent = reference.title || reference.id;
  renderMetadata(reference);
  renderSummarySections(reference);
  bindDetailEvents(reference);
  setPageState("ready");
}

function renderMetadata(reference) {
  const target = document.querySelector("[data-refscilink-metadata]");
  if (!target) return;
  target.textContent = "";
  [
    ["ID", reference.id],
    ["Number", reference.number],
    ["Authors", reference.authors?.join(", ")],
    ["Year", reference.year],
    ["Journal", reference.journal],
    ["DOI", reference.doi],
    ["PMID", reference.pmid],
    ["PMCID", reference.pmcid],
    ["Access", reference.access_type],
    ["Validation", getValidationStatus(reference)]
  ].forEach(([label, value]) => {
    if (!value) return;
    const dt = document.createElement("dt");
    const dd = document.createElement("dd");
    dt.textContent = label;
    dd.textContent = String(value);
    target.append(dt, dd);
  });
}

function renderSummarySections(reference) {
  const l = refscilinkState.labels;
  setSectionText("[data-refscilink-short-summary]", l.shortSummary, reference.short_summary);
  setSectionText("[data-refscilink-detailed-summary]", l.detailedSummary, reference.detailed_summary);
  setSectionList("[data-refscilink-key-points]", l.keyPoints, reference.key_points || []);
  setSectionText("[data-refscilink-project-relevance]", l.projectRelevance, reference.project_relevance);
  setSectionText("[data-refscilink-limitations]", l.limitations, reference.limitations);
}

function setSectionText(selector, title, value) {
  const section = document.querySelector(selector);
  if (!section) return;
  section.textContent = "";
  const heading = document.createElement("h3");
  const paragraph = document.createElement("p");
  heading.textContent = title;
  paragraph.textContent = value || refscilinkState.labels.pending;
  section.append(heading, paragraph);
}

function setSectionList(selector, title, values) {
  const section = document.querySelector(selector);
  if (!section) return;
  section.textContent = "";
  const heading = document.createElement("h3");
  const list = document.createElement("ul");
  heading.textContent = title;
  (values.length ? values : [refscilinkState.labels.pending]).forEach(value => {
    const item = document.createElement("li");
    item.textContent = value;
    list.appendChild(item);
  });
  section.append(heading, list);
}

// ==========================================================
// Filters, validation and utilities
// ==========================================================

function applyFilters(references) {
  const query = document.querySelector("[data-refscilink-search]")?.value.trim().toLowerCase() || "";
  const theme = document.querySelector("[data-refscilink-theme-filter]")?.value || "all";
  const validation = document.querySelector("[data-refscilink-validation-filter]")?.value || "all";
  const access = document.querySelector("[data-refscilink-access-filter]")?.value || "all";
  return references
    .filter(reference => theme === "all" || reference.theme === theme)
    .filter(reference => validation === "all" || getValidationStatus(reference) === validation)
    .filter(reference => access === "all" || reference.access_type === access)
    .filter(reference => !query || [reference.title, reference.authors?.join(" "), reference.journal, reference.year, reference.raw_reference].join(" ").toLowerCase().includes(query));
}

function bindIndexEvents() {
  ["[data-refscilink-search]", "[data-refscilink-theme-filter]", "[data-refscilink-validation-filter]", "[data-refscilink-access-filter]"].forEach(selector => {
    const element = document.querySelector(selector);
    if (!element || element.dataset.refscilinkBound) return;
    element.dataset.refscilinkBound = "true";
    element.addEventListener("input", renderFilteredReferences);
    element.addEventListener("change", renderFilteredReferences);
  });
}

function bindDetailEvents(reference) {
  document.querySelector("[data-refscilink-copy-reference]")?.addEventListener("click", () => copyReferenceToClipboard(reference));
  document.querySelector("[data-refscilink-validate]")?.addEventListener("click", () => validateReference(reference.id));
  const source = document.querySelector("[data-refscilink-source-link]");
  const href = getSafeExternalHref(reference);
  if (source && href) {
    source.href = href;
    source.target = "_blank";
    source.rel = "noopener noreferrer";
  }
  if (source && !href) {
    source.removeAttribute("href");
    source.hidden = true;
  }
}

function getReferenceIdFromUrl() {
  const params = new URLSearchParams(window.location.search);
  return params.get("id") || params.get("ref") || "";
}

function findReferenceById(id) {
  return refscilinkState.references.find(reference => reference.id === id);
}

async function copyReferenceToClipboard(reference) {
  const text = reference.raw_reference || reference.title || reference.id;
  try {
    await navigator.clipboard.writeText(text);
  } catch (error) {
    window.prompt(refscilinkState.labels.copyReference, text);
  }
}

function validateReference(id) {
  refscilinkState.validation[id] = {
    validated: true,
    validation_status: "validated",
    validated_at: new Date().toISOString()
  };
  saveValidationState();
  renderCurrentPage();
}

function getValidationStatus(reference) {
  return refscilinkState.validation[reference.id]?.validation_status || reference.validation_status || "pending_validation";
}

function loadValidationState() {
  try {
    return JSON.parse(localStorage.getItem(REFSCILINK_VALIDATION_STORAGE_KEY) || "{}");
  } catch {
    return {};
  }
}

function saveValidationState() {
  try {
    localStorage.setItem(REFSCILINK_VALIDATION_STORAGE_KEY, JSON.stringify(refscilinkState.validation));
  } catch {
    console.warn("RefSciLink: localStorage unavailable.");
  }
}

function setPageState(state) {
  const loading = document.querySelector("[data-refscilink-loading]");
  const empty = document.querySelector("[data-refscilink-empty]");
  const notFound = document.querySelector("[data-refscilink-not-found]");
  const detail = document.querySelector("[data-refscilink-detail]");
  if (loading) loading.hidden = state !== "loading";
  if (empty) empty.hidden = state !== "empty";
  if (notFound) notFound.hidden = state !== "not_found";
  if (detail) detail.hidden = state !== "ready";
}

function showError(error) {
  const target = document.querySelector("[data-refscilink-error]");
  if (target) {
    target.textContent = `${refscilinkState.labels.error} ${error.message}`;
    target.hidden = false;
  }
  setPageState("error");
  console.error("RefSciLink:", error);
}

function createBadge(text, className) {
  const badge = document.createElement("span");
  badge.className = className;
  badge.textContent = text || "unknown";
  return badge;
}

function createInternalLink(href, label) {
  const link = document.createElement("a");
  link.href = href;
  link.textContent = label;
  return link;
}

function createSourceLink(reference) {
  const href = getSafeExternalHref(reference);
  const link = document.createElement("a");
  link.textContent = refscilinkState.labels.viewSource;
  if (href) {
    link.href = href;
    link.target = "_blank";
    link.rel = "noopener noreferrer";
  } else {
    link.hidden = true;
  }
  return link;
}

function getSafeExternalHref(reference) {
  const candidates = [
    reference.url,
    reference.source_url,
    reference.pdf_url,
    getDoiHref(reference.doi),
    getPmidHref(reference.pmid),
    getPmcidHref(reference.pmcid)
  ].filter(Boolean);
  for (const href of candidates) {
    try {
      const parsed = new URL(href, window.location.href);
      if (REFSCILINK_ALLOWED_EXTERNAL_PROTOCOLS.has(parsed.protocol)) return parsed.href;
    } catch {
      // Invalid URLs are ignored so unsafe source values cannot break rendering.
    }
  }
  return "";
}

function getDoiHref(doi) {
  const normalized = String(doi || "")
    .trim()
    .replace(/^doi\s*:?\s*/i, "")
    .replace(/^https?:\/\/(?:dx\.)?doi\.org\//i, "");
  return normalized ? `https://doi.org/${encodeURI(normalized)}` : "";
}

function getPmidHref(pmid) {
  const normalized = String(pmid || "").trim().replace(/^PMID:?\s*/i, "");
  return normalized ? `https://pubmed.ncbi.nlm.nih.gov/${encodeURIComponent(normalized)}/` : "";
}

function getPmcidHref(pmcid) {
  const normalized = String(pmcid || "").trim().replace(/^PMC/i, "");
  return normalized ? `https://www.ncbi.nlm.nih.gov/pmc/articles/PMC${encodeURIComponent(normalized)}/` : "";
}

function createButton(label, handler) {
  const button = document.createElement("button");
  button.type = "button";
  button.textContent = label;
  button.addEventListener("click", handler);
  return button;
}

function normalizeClass(value = "unknown") {
  return String(value).replace(/_/g, "-").replace(/[^a-z0-9-]/gi, "").toLowerCase();
}

function renderCurrentPage() {
  const page = detectCurrentPage();
  if (page === "index") renderIndexPage();
  if (page === "detail") renderDetailPage();
}

// ==========================================================
// Bootstrapping
// ==========================================================

async function initRefSciLink() {
  try {
    setPageState("loading");
    refscilinkState.labels = getLocalizedLabels();
    applyI18n();
    refscilinkState.validation = loadValidationState();
    refscilinkState.references = await loadReferences();
    renderCurrentPage();
  } catch (error) {
    showError(error);
  }
}

document.addEventListener("DOMContentLoaded", initRefSciLink);
